"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

export function dataWorkspaceTypeBadgeClassName(type?: string): string {
  const normalizedType = (type ?? "text").toLowerCase()

  if (normalizedType === "enum" || normalizedType === "select") {
    return "border-amber-300/60 bg-amber-500/10 text-amber-700 dark:text-amber-300"
  }

  if (normalizedType === "uuid" || normalizedType === "foreign-key" || normalizedType === "link") {
    return "border-sky-300/60 bg-sky-500/10 text-sky-700 dark:text-sky-300"
  }

  if (normalizedType === "datetime" || normalizedType === "date") {
    return "border-violet-300/60 bg-violet-500/10 text-violet-700 dark:text-violet-300"
  }

  if (normalizedType === "boolean") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (normalizedType === "json") {
    return "border-rose-300/60 bg-rose-500/10 text-rose-700 dark:text-rose-300"
  }

  return "border-border/70 bg-muted/45 text-muted-foreground"
}

export function dataWorkspaceMetaBadgeClassName(tone: "default" | "primary" | "success" | "danger" = "default"): string {
  if (tone === "primary") {
    return "border-border/70 bg-foreground/[0.06] text-foreground"
  }

  if (tone === "success") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (tone === "danger") {
    return "border-destructive/25 bg-destructive/10 text-destructive"
  }

  return "border-border/70 bg-background/70 text-muted-foreground"
}

export function dataWorkspaceRelationBadgeClassName(source?: string): string {
  if (source === "base") {
    return "border-border/70 bg-background/80 text-foreground"
  }

  return "border-border/70 bg-muted/50 text-muted-foreground"
}

export function dataWorkspaceRowClassName(options?: {
  interactive?: boolean
  selected?: boolean
}): string {
  return cn(
    "group border-b transition-colors",
    options?.interactive && "cursor-pointer hover:bg-muted/50",
    options?.selected && "bg-muted hover:bg-muted/70",
  )
}

export interface DataWorkspaceHeaderProps {
  eyebrow?: React.ReactNode
  title: React.ReactNode
  description?: React.ReactNode
  meta?: React.ReactNode
  actions?: React.ReactNode
  className?: string
}

export function DataWorkspaceHeader({
  eyebrow,
  title,
  description,
  meta,
  actions,
  className,
}: DataWorkspaceHeaderProps) {
  return (
    <div className={cn("flex flex-col gap-1.5 sm:flex-row sm:items-center sm:justify-between", className)}>
      <div className="min-w-0 space-y-1">
        <div className="space-y-1">
          {eyebrow ? (
            <p className="text-xs font-medium text-muted-foreground">
              {eyebrow}
            </p>
          ) : null}
          <h3 className="text-lg font-semibold leading-none tracking-tight">
            {title}
          </h3>
          {description ? (
            <p className="text-sm text-muted-foreground">
              {description}
            </p>
          ) : null}
        </div>
        {meta ? (
          <div className="flex flex-wrap items-center gap-1.5 text-xs text-muted-foreground pt-1">
            {meta}
          </div>
        ) : null}
      </div>
      {actions ? (
        <div className="flex shrink-0 flex-wrap items-center gap-2">
          {actions}
        </div>
      ) : null}
    </div>
  )
}

type DataStateTone = "neutral" | "danger" | "success"

export interface DataWorkspaceStateProps extends React.HTMLAttributes<HTMLDivElement> {
  tone?: DataStateTone
  heading?: React.ReactNode
  description: React.ReactNode
}

export function DataWorkspaceState({
  tone = "neutral",
  heading,
  description,
  className,
  ...props
}: DataWorkspaceStateProps) {
  return (
    <div
      className={cn(
        "rounded-lg border p-4 text-sm",
        tone === "danger" && "border-destructive/50 bg-destructive/10 text-destructive",
        tone === "success" && "border-emerald-500/30 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300",
        tone === "neutral" && "border-dashed text-muted-foreground",
        className,
      )}
      {...props}
    >
      <div className="grid gap-1">
        {heading ? (
          <p className="font-medium text-foreground">{heading}</p>
        ) : null}
        <div className={tone === "neutral" ? "text-muted-foreground" : undefined}>
          {description}
        </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRelatedRecords, type RelatedRecordsInclude } from "lemma-sdk/react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardHeader,
} from "@/components/ui/card"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import { cn } from "@/lib/utils"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
  dataWorkspaceMetaBadgeClassName,
  dataWorkspaceRelationBadgeClassName,
  dataWorkspaceRowClassName,
} from "@/components/lemma/registry-data-workspace"

export interface LemmaRelatedRecordsTableProps extends React.HTMLAttributes<HTMLDivElement> {
  client: LemmaClient
  podId?: string
  tableName: string
  include: RelatedRecordsInclude[]
  baseFields?: string[]
  limit?: number
  title?: string
  description?: string
  emptyText?: string
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  if (value === null || typeof value === "undefined") return "—"

  try {
    return JSON.stringify(value)
  } catch {
    return String(value)
  }
}

function readColumnValue(record: Record<string, unknown>, column: {
  source: "base" | "related"
  field: string
  relationKey?: string
}): unknown {
  if (column.source === "base") {
    return record[column.field]
  }

  const relatedRecord = column.relationKey ? record[column.relationKey] : undefined
  if (!relatedRecord || typeof relatedRecord !== "object" || Array.isArray(relatedRecord)) {
    return undefined
  }

  return (relatedRecord as Record<string, unknown>)[column.field]
}

export const LemmaRelatedRecordsTable = React.forwardRef<HTMLDivElement, LemmaRelatedRecordsTableProps>(
  ({
    client,
    podId,
    tableName,
    include,
    baseFields,
    limit = 10,
    title,
    description,
    emptyText = "No related records were found for this relation setup.",
    className,
    ...props
  }, ref) => {
    const trimmedTableName = tableName.trim()
    const relatedState = useRelatedRecords({
      client,
      podId,
      tableName: trimmedTableName,
      include,
      baseFields,
      limit,
      enabled: trimmedTableName.length > 0 && include.length > 0,
    })

    if (!trimmedTableName || include.length === 0) {
      return (
        <Card ref={ref} className={cn("", className)} {...props}>
          <CardHeader>
            <DataWorkspaceHeader
              description={description ?? "Choose a table with a foreign key to preview related data."}
              eyebrow="Relations"
              title={title ?? "Related Records"}
            />
          </CardHeader>
        </Card>
      )
    }

    return (
      <Card ref={ref} className={cn("", className)} {...props}>
        <CardHeader>
          <DataWorkspaceHeader
            actions={(
              <Button
                disabled={relatedState.isLoading}
                onClick={() => {
                  void relatedState.refresh()
                }}
                type="button"
                variant="ghost"
              >
                {relatedState.isLoading ? "Refreshing..." : "Refresh"}
              </Button>
            )}
            description={description ?? "Relation-aware joined records powered by foreign-key metadata."}
            eyebrow="Relations"
            meta={(
              <>
                <Badge className={cn("rounded-full border px-2 py-0.5 text-xs", dataWorkspaceMetaBadgeClassName("primary"))} variant="outline">
                  {trimmedTableName}
                </Badge>
                <Badge className={cn("rounded-full border px-2 py-0.5 text-xs", dataWorkspaceMetaBadgeClassName("default"))} variant="outline">
                  {relatedState.records.length} joined
                </Badge>
              </>
            )}
            title={title ?? `Related Records: ${trimmedTableName}`}
          />
        </CardHeader>
        <CardContent className="flex flex-col gap-4">
          {relatedState.error ? (
            <DataWorkspaceState description={relatedState.error.message} tone="danger" />
          ) : null}

          {relatedState.isLoading && relatedState.records.length === 0 ? (
            <DataWorkspaceState description="Loading related records..." heading="Fetching joined rows" />
          ) : null}

          {!relatedState.isLoading && relatedState.records.length === 0 ? (
            <DataWorkspaceState description={emptyText} heading="No related rows" />
          ) : null}

          {relatedState.records.length > 0 && relatedState.columns.length > 0 ? (
            <div className="rounded-lg border">
              <Table>
                <TableHeader className="bg-muted/50">
                  <TableRow className="hover:bg-transparent">
                    {relatedState.columns.map((column) => (
                      <TableHead key={column.key} className="align-top border-b px-4 py-3">
                        <div className="grid gap-2">
                          <div className="text-sm font-medium text-foreground">{column.label}</div>
                          <Badge className={cn("w-fit rounded-full border px-2 py-0.5 text-xs", dataWorkspaceRelationBadgeClassName(column.source))} variant="outline">
                            {column.source === "base" ? "Base" : column.relationKey ?? "Related"}
                          </Badge>
                        </div>
                      </TableHead>
                    ))}
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {relatedState.records.map((record, index) => (
                    <TableRow key={index} className={dataWorkspaceRowClassName()}>
                      {relatedState.columns.map((column) => {
                        const value = readColumnValue(record, column)
                        return (
                          <TableCell key={column.key} className="max-w-[240px] px-4 py-3 align-top">
                            <div className="truncate text-sm leading-6 text-foreground/90" title={formatValue(value)}>
                              {formatValue(value)}
                            </div>
                          </TableCell>
                        )
                      })}
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          ) : null}
        </CardContent>
      </Card>
    )
  },
)
LemmaRelatedRecordsTable.displayName = "LemmaRelatedRecordsTable"
